const histAtual = String($('select_conversa').first().json?.historico || '');
const userMsg = String($('normalize_phone').first().json?.mensagem_texto || '');

// Tenta agente_principal primeiro, fallback build_resposta_ativa
let agenteResp = null;
try { agenteResp = $('agente_principal').first().json; } catch(e) {}
let agentText = String(agenteResp?.content?.[0]?.text || '');

if (!agentText) {
  try {
    const r = $('build_resposta_ativa').first().json;
    agentText = String(r?.content?.[0]?.text || '');
  } catch(e) {}
}

const novoTurn = `|||TURN|||Cliente: ${userMsg}\nClaude: ${agentText}`;
const completo = histAtual + novoTurn;
const turns = completo.split('|||TURN|||');
const ultimos20 = turns.slice(-20).join('|||TURN|||');

return [{
  json: {
    historico_atualizado: ultimos20,
    classifier_result: 'PENDENTE',
    agente_resposta: agentText,
    telefone: $('normalize_phone').first().json.telefone_normalizado
  }
}];

// Extrai JSON da resposta do extrator (pode vir embrulhado em markdown ```json...```)
const raw = $('extrator').first().json.message?.content?.[0]?.text
         || $('extrator').first().json.content?.[0]?.text
         || '';

let cleaned = raw.trim();
// Remove blocos de código markdown
cleaned = cleaned.replace(/^```(?:json)?\s*/i, '').replace(/```\s*$/, '').trim();
// Procura primeiro { e último } pra ser tolerante
const firstBrace = cleaned.indexOf('{');
const lastBrace = cleaned.lastIndexOf('}');
if (firstBrace >= 0 && lastBrace > firstBrace) {
  cleaned = cleaned.substring(firstBrace, lastBrace + 1);
}

let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch (e) {
  return [{json: {parse_error: e.message, raw: raw.substring(0, 500), json_extrator: null}}];
}

return [{json: {json_extrator: parsed, parse_ok: true}}];

const cliente = $('select_cliente').first().json;
const estado = $('resolve_geo_criacao').first().json.estado;
const json = estado.brief;
const errors = [];

if (!json || Object.keys(json).length === 0) {
  errors.push('brief vazio (parse falhou ou extrator não rodou)');
  return [{ json: { ok: false, motivos: errors, estado } }];
}

const verba = parseInt(json.campanha?.verba_diaria);
if (isNaN(verba) || verba < 10) errors.push('verba_diaria < 10');
if (verba > 100) errors.push('verba_diaria > 100');
if (!json.campanha?.objetivo_meta) errors.push('objetivo_meta vazio');
if (!json.conjunto?.geo) errors.push('geo vazio');
if (!json.publico_escolhido) errors.push('publico_escolhido vazio');
if (!estado.criativo?.recebido || !estado.criativo?.url) errors.push('criativo_url vazio');
if (!cliente?.ad_account_id) errors.push('ad_account_id vazio');
if (!json.targeting_meta) errors.push('targeting_meta vazio');
if (!json.targeting_meta?.geo_locations) errors.push('geo_locations vazio');

// Segurança anti-Brasil-total: bloqueia se geo_locations só tem countries (sem cidade)
if (json.targeting_meta?.geo_locations) {
  const gLoc = json.targeting_meta.geo_locations;
  const semCidade = !gLoc.cities?.length && !gLoc.regions?.length;
  if (gLoc.countries && semCidade) {
    errors.push('localização não definida — campanha cobriria o Brasil inteiro. Informe o bairro/cidade/região exata do imóvel.');
  }
}

const conversaLike = {
  telefone: $('normalize_phone').first().json.telefone_normalizado,
  criativo_url: estado.criativo?.url || ''
};

return [{
  json: {
    ok: errors.length === 0,
    motivos: errors,
    json_extrator: json,
    cliente,
    conversa: conversaLike,
    estado,
    verba_em_centavos: Math.max((verba || 30) * 100, 1000)
  }
}];

// FINISH do criativo: recebe o upload feito pelo nó nativo meta_d3_upload
// (video_id ou image_hash) e cria o adcreative. Vídeo: espera processar + pega thumbnail.
const prep = $('meta_d3_prep').first().json;
if (prep.error) return [{ json: { error: prep.error } }];

const token = prep.token, adAccountId = prep.adAccountId, pageId = prep.pageId;
const campNome = prep.campNome, copy = prep.copy;
const apiBase = 'https://graph.facebook.com/v25.0';
const up = $('meta_d3_upload').first().json;

async function getJson(url) {
  const r = await this.helpers.httpRequest({ method: 'GET', url, returnFullResponse: false });
  return (typeof r === 'string') ? JSON.parse(r) : r;
}
async function postJson(url, body) {
  try {
    return await this.helpers.httpRequest({ method: 'POST', url, headers: { 'Content-Type': 'application/json' }, body, json: true, returnFullResponse: false });
  } catch (e) {
    const d = e?.response?.data || e?.response?.body || e?.message || String(e);
    throw new Error('Meta API error: ' + (typeof d === 'string' ? d : JSON.stringify(d)));
  }
}

if (prep.isVideo) {
  const videoId = up && up.id;
  if (!videoId) return [{ json: { error: 'video_upload_falhou', resp: up } }];

  // espera o vídeo processar
  let st = null;
  for (let i = 0; i < 8; i++) {
    await new Promise(r => setTimeout(r, 4000));
    const s = await getJson.call(this, `${apiBase}/${videoId}?fields=status&access_token=${encodeURIComponent(token)}`);
    st = s?.status?.video_status || s?.status;
    if (st === 'ready') break;
    if (st === 'error') return [{ json: { error: 'video_processing_error', video_id: videoId, status: s } }];
  }
  if (st !== 'ready') return [{ json: { error: 'video_processing_timeout', video_id: videoId } }];

  // thumbnail (obrigatória no video_data)
  let thumb = null;
  try {
    const th = await getJson.call(this, `${apiBase}/${videoId}/thumbnails?access_token=${encodeURIComponent(token)}`);
    const list = th.data || [];
    const pref = list.find(t => t.is_preferred) || list[0];
    if (pref && pref.uri) thumb = pref.uri;
  } catch (e) {}
  if (!thumb) return [{ json: { error: 'video_sem_thumbnail', video_id: videoId } }];

  const videoData = {
    video_id: videoId, title: campNome, message: copy, image_url: thumb,
    call_to_action: { type: 'WHATSAPP_MESSAGE', value: { app_destination: 'WHATSAPP' } },
  };
  const cr = await postJson.call(this, `${apiBase}/act_${adAccountId}/adcreatives`, {
    name: campNome, object_story_spec: { page_id: pageId, video_data: videoData }, access_token: token,
  });
  if (!cr.id) return [{ json: { error: 'video_creative_falhou', resp: cr } }];
  return [{ json: { id: cr.id, tipo_criativo: 'video', video_id: videoId } }];

} else {
  const hash = (up && up.images) ? Object.values(up.images)[0]?.hash : null;
  if (!hash) return [{ json: { error: 'image_upload_falhou', resp: up } }];
  const linkData = {
    message: copy, image_hash: hash,
    call_to_action: { type: 'WHATSAPP_MESSAGE', value: { app_destination: 'WHATSAPP' } },
  };
  const cr = await postJson.call(this, `${apiBase}/act_${adAccountId}/adcreatives`, {
    name: campNome, object_story_spec: { page_id: pageId, link_data: linkData }, access_token: token,
  });
  if (!cr.id) return [{ json: { error: 'image_creative_falhou', resp: cr } }];
  return [{ json: { id: cr.id, tipo_criativo: 'image', image_hash: hash } }];
}

const body = $input.first().json.body || {};
const raw = body.chat?.phone || body.message?.sender_pn?.split('@')[0] || body.message?.from || '';
const normalized = String(raw).replace(/[+\s\-@]/g, '').replace(/s.whatsapp.net.*$/, '');
return [{
  json: {
    ...$input.first().json,
    telefone_normalizado: normalized,
    message_id: body.message?.id || ''
  }
}];

// Cloud API: media_get_url devolve {url, mime_type}. Emite fileURL/mimetype (compat)
// + media_id (fonte de verdade pra re-buscar o criativo na hora de criar o anúncio).
const g = $input.first().json || {};
let media_id = '';
try { media_id = $('media_normalize_phone').item.json.message_id || ''; } catch (e) {}
return [{ json: { fileURL: g.url || '', mimetype: g.mime_type || '', media_id } }];

const system = "Você é um EXTRATOR de dados de campanha. Sua única função é ler a conversa completa abaixo entre o agente de tráfego da Quirk e o cliente, e extrair a estrutura final da campanha que o cliente confirmou.

CONVERSA COMPLETA:
>>>{{ $node['select_conversa'].json.historico }}<<<

REGRAS GERAIS:
- Responda APENAS com um objeto JSON válido. Nada antes, nada depois. Sem marcadores de código (sem crase tripla), sem explicação, sem comentário.
- Preencha cada campo com o dado REAL extraído da conversa.
- Verba diária (verba_diaria) e valor do imóvel (valor_imovel): devolva SEMPRE um NÚMERO INTEIRO, sem "R$", sem pontos de milhar, sem aspas. Exemplos válidos: 30, 50, 100, 450000, 1500000.
- CRÍTICO sobre verba_diaria: nunca devolva null ou string. Se o cliente disse "confirma" sem citar verba específica, use o valor MENOR da faixa que o agente sugeriu (ex: agente sugeriu "R$ 70-100/dia" → use 70). Se nenhuma verba foi citada na conversa inteira, use 30 como padrão (R$ 30/dia, valor seguro mínimo). NUNCA use o valor maior — começamos com o piso pra não comprometer verba do cliente.

REGRAS ESPECIAIS (sempre aplique):
- objetivo_meta: SEMPRE "OUTCOME_LEADS". Todas as campanhas da Quirk Auto Ads são de mensagem CTWA (Click-to-WhatsApp). Na API da Meta, isso usa objective OUTCOME_LEADS no nível da campanha, e CONVERSATIONS + WHATSAPP no nível do conjunto. O Extrator sempre devolve OUTCOME_LEADS aqui.
- publico_escolhido: deve coincidir com o NOME EXATO de um item da TABELA DE PÚBLICOS abaixo. Se o agente nominou (ex: "Pub Quirk 4"), use literal. Se NÃO houver nome formal mas o cliente confirmou trilho + faixa de valor, deduza o publico pela regra: objetivo investimento/investidor → "Pub Quirk Invest"; veraneio/segunda casa → "Pub Quirk Veraneio"; moradia+acima_1mi+precisao → "Pub Quirk 4"; moradia+acima_1mi+alcance → "Pub Quirk 3"; moradia+700k_1mi → "Pub Quirk 2"; moradia+ate_700k → "Pub Quirk 1.1"; primeira moradia → "Pub Quirk Primeira Moradia"; profissao alta renda → "Pub Quirk Profissoes"; corretor → "Pub Corretores". Em ultima instancia (sem dado), use "Pub Quirk 0".
- nome da campanha: extraia EXATAMENTE como o cliente definiu na conversa. Não reformule.
- copy: gere a legenda do anuncio na ESTRUTURA DE FICHA IMOBILIARIA da Quirk, usando SOMENTE fatos ditos na conversa (NUNCA invente metragem, vagas, banheiros ou specs — inventar dado de imovel e propaganda enganosa, proibido). Formato com quebras de linha entre os blocos: HEADLINE (emoji de casa + tipo do imovel + bairro + ' — R$ ' + valor + ' 🔥'); depois UMA LINHA por atributo/diferencial que o cliente deu, cada uma comecando com '✅ '; depois uma linha '📍 ' com o bairro/regiao (e proximidades se ditas); por fim a CTA numa linha: 'Chama aqui no WhatsApp e agende sua visita! 👇'. NUNCA escreva 'clique no link' nem 'cadastre-se' (o anuncio tem botao de WhatsApp, nao link). Nao deixe vazio.
- periodo: se não foi definido, use "15 dias" como padrão Quirk.

REGRA DE TARGETING_META (CRÍTICA):
O campo "targeting_meta" deve ser preenchido conforme a TABELA DE PÚBLICOS abaixo, usando o valor de "publico_escolhido" como chave. Copie o objeto JSON da tabela EXATAMENTE como está, depois ajuste age_min/age_max e geo_locations se o cliente confirmou valores diferentes na conversa.

Se o cliente mencionou cidade específica (ex: "Curitiba", "São Paulo"), substitua:
  "geo_locations": {"countries": ["BR"]}
por:
  "geo_locations": {"cities": [{"name": "Curitiba, BR"}]}

Se o cliente mencionou raio (ex: "30km da Gleba Palhano"), adicione "radius": 30 e "distance_unit": "kilometer" dentro do objeto da cidade.

REGRA CRÍTICA DE TIPOS NO JSON DE SAÍDA (sob pena de quebrar a campanha na Meta):
- Os campos numéricos do "targeting_meta" — age_min, age_max — DEVEM ser INTEIROS JSON (sem aspas, sem ponto, sem string). Exemplo VÁLIDO: "age_min":25 ; "age_max":60 . Exemplo INVÁLIDO: "age_min":"25" ; "age_max":null .
- O campo verba_diaria DEVE ser INTEIRO JSON. Exemplo VÁLIDO: "verba_diaria":30 . INVÁLIDO: "verba_diaria":"30" ou null.
- O campo valor_imovel DEVE ser INTEIRO JSON. Mesmas regras.
- Se algum desses campos não puder ser deduzido, NUNCA devolva null — use o valor padrão da tabela (age_min:25, age_max:60, verba_diaria:30, valor_imovel:0).

REGRA CRÍTICA DE GEO_LOCATIONS:
O cliente DEVE ter informado uma localização brasileira (cidade, bairro, distrito ou região) + raio em km. Extraia:
- conjunto.geo (string descritiva: "Brasílândia, SP, raio 5km")
- conjunto.geo_cidade (nome EXATO mencionado pelo cliente — pode ser bairro/distrito)
- conjunto.geo_estado (UF "SP"/"RJ"/... OU nome "São Paulo"; vazio se não mencionado)
- conjunto.geo_raio_km (inteiro entre 1 e 80 — NÃO clampe pra 17; sistema pós-processa raios menores via lat/lng)

Em "targeting_meta.geo_locations", monte um placeholder usando a TABELA DE CIDADES BR. O sistema vai sobrescrever depois com resolução dinâmica via Meta Search + Nominatim, então esse campo é só fallback inicial:
  "geo_locations": {"cities": [{"key": "<KEY>", "radius": <raio_km>, "distance_unit": "kilometer"}]}

Se cidade não estiver na tabela, use a CAPITAL do estado mencionado (ou "269969" São Paulo se não souber). NUNCA caia em {"countries":["BR"]} — o pós-processador resolve a localização real depois.

