const histAtual = String($('select_conversa').first().json?.historico || '');
const userMsg = String($('normalize_phone').first().json?.mensagem_texto || '');

// Tenta agente_principal primeiro, fallback build_resposta_ativa
let agenteResp = null;
try { agenteResp = $('agente_principal').first().json; } catch(e) {}
let agentText = String(agenteResp?.content?.[0]?.text || '');

if (!agentText) {
  try {
    const r = $('build_resposta_ativa').first().json;
    agentText = String(r?.content?.[0]?.text || '');
  } catch(e) {}
}

const novoTurn = `|||TURN|||Cliente: ${userMsg}\nClaude: ${agentText}`;
const completo = histAtual + novoTurn;
const turns = completo.split('|||TURN|||');
const ultimos20 = turns.slice(-20).join('|||TURN|||');

return [{
  json: {
    historico_atualizado: ultimos20,
    classifier_result: 'PENDENTE',
    agente_resposta: agentText,
    telefone: $('normalize_phone').first().json.telefone_normalizado
  }
}];

// Extrai JSON da resposta do extrator (pode vir embrulhado em markdown ```json...```)
const raw = $('extrator').first().json.message?.content?.[0]?.text
         || $('extrator').first().json.content?.[0]?.text
         || '';

let cleaned = raw.trim();
// Remove blocos de código markdown
cleaned = cleaned.replace(/^```(?:json)?\s*/i, '').replace(/```\s*$/, '').trim();
// Procura primeiro { e último } pra ser tolerante
const firstBrace = cleaned.indexOf('{');
const lastBrace = cleaned.lastIndexOf('}');
if (firstBrace >= 0 && lastBrace > firstBrace) {
  cleaned = cleaned.substring(firstBrace, lastBrace + 1);
}

let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch (e) {
  return [{json: {parse_error: e.message, raw: raw.substring(0, 500), json_extrator: null}}];
}

return [{json: {json_extrator: parsed, parse_ok: true}}];

const cliente = $('select_cliente').first().json;
const estado = $('resolve_geo_criacao').first().json.estado;
const json = estado.brief;
const errors = [];

if (!json || Object.keys(json).length === 0) {
  errors.push('brief vazio (parse falhou ou extrator não rodou)');
  return [{ json: { ok: false, motivos: errors, estado } }];
}

const verba = parseInt(json.campanha?.verba_diaria);
if (isNaN(verba) || verba < 10) errors.push('verba_diaria < 10');
if (verba > 100) errors.push('verba_diaria > 100');
if (!json.campanha?.objetivo_meta) errors.push('objetivo_meta vazio');
if (!json.conjunto?.geo) errors.push('geo vazio');
if (!json.publico_escolhido) errors.push('publico_escolhido vazio');
if (!estado.criativo?.recebido || !estado.criativo?.url) errors.push('criativo_url vazio');
if (!cliente?.ad_account_id) errors.push('ad_account_id vazio');
if (!json.targeting_meta) errors.push('targeting_meta vazio');
if (!json.targeting_meta?.geo_locations) errors.push('geo_locations vazio');

// Segurança anti-Brasil-total: bloqueia se geo_locations só tem countries (sem cidade)
if (json.targeting_meta?.geo_locations) {
  const gLoc = json.targeting_meta.geo_locations;
  const semCidade = !gLoc.cities?.length && !gLoc.regions?.length;
  if (gLoc.countries && semCidade) {
    errors.push('localização não definida — campanha cobriria o Brasil inteiro. Informe o bairro/cidade/região exata do imóvel.');
  }
}

const conversaLike = {
  telefone: $('normalize_phone').first().json.telefone_normalizado,
  criativo_url: estado.criativo?.url || ''
};

return [{
  json: {
    ok: errors.length === 0,
    motivos: errors,
    json_extrator: json,
    cliente,
    conversa: conversaLike,
    estado,
    verba_em_centavos: Math.max((verba || 30) * 100, 1000)
  }
}];

// FINISH do criativo: recebe o upload feito pelo nó nativo meta_d3_upload
// (video_id ou image_hash) e cria o adcreative. Vídeo: espera processar + pega thumbnail.
const prep = $('meta_d3_prep').first().json;
if (prep.error) return [{ json: { error: prep.error } }];

const token = prep.token, adAccountId = prep.adAccountId, pageId = prep.pageId;
const campNome = prep.campNome, copy = prep.copy;
const apiBase = 'https://graph.facebook.com/v25.0';
const up = $('meta_d3_upload').first().json;

async function getJson(url) {
  const r = await this.helpers.httpRequest({ method: 'GET', url, returnFullResponse: false });
  return (typeof r === 'string') ? JSON.parse(r) : r;
}
async function postJson(url, body) {
  try {
    return await this.helpers.httpRequest({ method: 'POST', url, headers: { 'Content-Type': 'application/json' }, body, json: true, returnFullResponse: false });
  } catch (e) {
    const d = e?.response?.data || e?.response?.body || e?.message || String(e);
    throw new Error('Meta API error: ' + (typeof d === 'string' ? d : JSON.stringify(d)));
  }
}

if (prep.isVideo) {
  const videoId = up && up.id;
  if (!videoId) return [{ json: { error: 'video_upload_falhou', resp: up } }];

  // espera o vídeo processar
  let st = null;
  for (let i = 0; i < 8; i++) {
    await new Promise(r => setTimeout(r, 4000));
    const s = await getJson.call(this, `${apiBase}/${videoId}?fields=status&access_token=${encodeURIComponent(token)}`);
    st = s?.status?.video_status || s?.status;
    if (st === 'ready') break;
    if (st === 'error') return [{ json: { error: 'video_processing_error', video_id: videoId, status: s } }];
  }
  if (st !== 'ready') return [{ json: { error: 'video_processing_timeout', video_id: videoId } }];

  // thumbnail (obrigatória no video_data)
  let thumb = null;
  try {
    const th = await getJson.call(this, `${apiBase}/${videoId}/thumbnails?access_token=${encodeURIComponent(token)}`);
    const list = th.data || [];
    const pref = list.find(t => t.is_preferred) || list[0];
    if (pref && pref.uri) thumb = pref.uri;
  } catch (e) {}
  if (!thumb) return [{ json: { error: 'video_sem_thumbnail', video_id: videoId } }];

  const videoData = {
    video_id: videoId, title: campNome, message: copy, image_url: thumb,
    call_to_action: { type: 'WHATSAPP_MESSAGE', value: { app_destination: 'WHATSAPP' } },
  };
  const cr = await postJson.call(this, `${apiBase}/act_${adAccountId}/adcreatives`, {
    name: campNome, object_story_spec: { page_id: pageId, video_data: videoData }, access_token: token,
  });
  if (!cr.id) return [{ json: { error: 'video_creative_falhou', resp: cr } }];
  return [{ json: { id: cr.id, tipo_criativo: 'video', video_id: videoId } }];

} else {
  const hash = (up && up.images) ? Object.values(up.images)[0]?.hash : null;
  if (!hash) return [{ json: { error: 'image_upload_falhou', resp: up } }];
  const linkData = {
    message: copy, image_hash: hash,
    call_to_action: { type: 'WHATSAPP_MESSAGE', value: { app_destination: 'WHATSAPP' } },
  };
  const cr = await postJson.call(this, `${apiBase}/act_${adAccountId}/adcreatives`, {
    name: campNome, object_story_spec: { page_id: pageId, link_data: linkData }, access_token: token,
  });
  if (!cr.id) return [{ json: { error: 'image_creative_falhou', resp: cr } }];
  return [{ json: { id: cr.id, tipo_criativo: 'image', image_hash: hash } }];
}

const body = $input.first().json.body || {};
const raw = body.chat?.phone || body.message?.sender_pn?.split('@')[0] || body.message?.from || '';
const normalized = String(raw).replace(/[+\s\-@]/g, '').replace(/s.whatsapp.net.*$/, '');
