    function parseGeoLivre(s) {
      const txt = String(s || '').trim();
      // 1) Raio: número antes de 'km' (ou no fim isolado)
      let raio = null;
      const mRaio = txt.match(/(\d+(?:[.,]\d+)?)\s*km/i) || txt.match(/(\d+(?:[.,]\d+)?)\s*$/);
