      // 2) UF: 2 letras maiúsculas isoladas (não confundir com palavra colada)
      let uf = null;
      const mUF = txt.match(/(?:^|[\s,\/])([A-Z]{2})(?=[\s,\/]|$)/);
      if (mUF) uf = mUF[1];
      // 3) Cidade: texto antes do raio (ou do UF se anterior), limpando ruídos
      let cidade = txt;
