      cidade = cidade.replace(/[,]?\s*raio\s*(de\s*)?\d+(?:[.,]\d+)?\s*km\s*$/i, '');
      // remove sufixo de raio puro
      cidade = cidade.replace(/[,]?\s*\d+(?:[.,]\d+)?\s*km\s*$/i, '');
      cidade = cidade.replace(/[,]?\s*\d+(?:[.,]\d+)?\s*$/, '');
      // remove UF do fim (ex: "Pinheiros SP" → "Pinheiros")
      if (uf) cidade = cidade.replace(new RegExp('[,\\s\\/]+' + uf + '\\s*$'), '');
      // se UF detectado, remove também o nome completo do estado da cidade (ex: "Brasilandia, São Paulo" + uf=SP → "Brasilandia")
      if (uf) {
        const UF_TO_NOME = {AC:'Acre',AL:'Alagoas',AP:'Amapá|Amapa',AM:'Amazonas',BA:'Bahia',CE:'Ceará|Ceara',DF:'Distrito Federal',ES:'Espírito Santo|Espirito Santo',GO:'Goiás|Goias',MA:'Maranhão|Maranhao',MT:'Mato Grosso',MS:'Mato Grosso do Sul',MG:'Minas Gerais',PA:'Pará|Para',PB:'Paraíba|Paraiba',PR:'Paraná|Parana',PE:'Pernambuco',PI:'Piauí|Piaui',RJ:'Rio de Janeiro',RN:'Rio Grande do Norte',RS:'Rio Grande do Sul',RO:'Rondônia|Rondonia',RR:'Roraima',SC:'Santa Catarina',SP:'São Paulo|Sao Paulo',SE:'Sergipe',TO:'Tocantins'};
        const nomeRe = UF_TO_NOME[uf];
        if (nomeRe) {
          cidade = cidade.replace(new RegExp(',\\s*(' + nomeRe + ')\\s*$', 'i'), '');
        }
      }
      // remove prefixo "bairro:" / "localização:" / "regiao:" etc
      cidade = cidade.replace(/^(bairro|localiza[çc][aã]o|regi[aã]o|cidade)\s*:\s*/i, '');
      // remove vírgula trailing
      cidade = cidade.replace(/[,\s]+$/, '').trim();
      return { cidade: cidade || txt, uf, raio };
    }

    let cidade_display, uf_display, raio_display;
    if (nv?.tipo === 'geo_estruturado') {
